import { useEffect, useState } from "react";
import axiosInstance from "../axiosConfig";

const Tasks = () => {
  const [plans, setPlans] = useState([]);
  const [subscriptions, setSubscriptions] = useState([]);
  const [selectedPlan, setSelectedPlan] = useState("");

  const fetchPlans = async () => {
    try {
      const res = await axiosInstance.get("/api/plans");
      setPlans(res.data);
    } catch (error) {
      console.error(error);
      alert("Failed to load plans");
    }
  };

  const fetchSubscriptions = async () => {
    try {
      const res = await axiosInstance.get("/api/subscriptions");
      setSubscriptions(res.data);
    } catch (error) {
      console.error(error);
      alert("Failed to load subscriptions");
    }
  };

  const handleSubscribe = async () => {
    if (!selectedPlan) {
      return alert("Please select a plan");
    }

    try {
      await axiosInstance.post("/api/subscriptions", {
        plan: selectedPlan,
      });

      alert("Subscription successful");
      fetchSubscriptions();
    } catch (error) {
      console.error(error);
      alert("Subscription failed");
    }
  };

  const handleDelete = async (id) => {
    try {
      await axiosInstance.delete(`/api/subscriptions/${id}`);
      fetchSubscriptions();
    } catch (error) {
      console.error(error);
      alert("Failed to cancel subscription");
    }
  };

  useEffect(() => {
    fetchPlans();
    fetchSubscriptions();
  }, []);

  return (
    <div className="container">
      
      {/* HEADER */}
      <div style={{ textAlign: "center", marginBottom: "25px" }}>
        <h1 style={{ fontSize: "26px" }}>Subscription Management</h1>
        <p style={{ color: "#6b7280", fontSize: "14px" }}>
          Choose and manage your plans
        </p>
      </div>

      {/* SELECT PLAN */}
      <div className="card">
        <h2 style={{ marginBottom: "12px" }}>Subscribe to a Plan</h2>

        <select
          value={selectedPlan}
          onChange={(e) => setSelectedPlan(e.target.value)}
        >
          <option value="">Select a Plan</option>
          {plans.map((plan) => (
            <option key={plan._id} value={plan._id}>
              {plan.name} - ${plan.price}
            </option>
          ))}
        </select>

        <button
          onClick={handleSubscribe}
          className="btn-success"
        >
          Subscribe
        </button>
      </div>

      {/* SUBSCRIPTIONS */}
      <div style={{ marginTop: "20px" }}>
        <h2 style={{ textAlign: "center", marginBottom: "15px" }}>
          My Subscriptions
        </h2>

        {subscriptions.length === 0 && (
          <p style={{ textAlign: "center", color: "#777" }}>
            No subscriptions yet
          </p>
        )}

        {subscriptions.map((sub) => (
          <div key={sub._id} className="card">
            <div className="flex">
              <div>
                <h3>{sub.plan?.name || "Plan"}</h3>
                <p style={{ color: "#555" }}>
                  Status: {sub.status}
                </p>
              </div>

              <button
                onClick={() => handleDelete(sub._id)}
                className="btn-danger"
                style={{ width: "auto" }}
              >
                Cancel
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Tasks;
